#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, count = 0, zero = 0;
        scanf("%d", &n);
        for (int i = 0; i < n; i++) {
            int x;
            scanf("%d", &x);
            if (x == 0) zero++;
            else count++;
        }
        printf("%d\n", (zero < count + 1) ? zero : count + 1);
    }
    return 0;
}

