code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int count = 0, zero = 0;
            for (int i = 0; i < n; i++) {
                int x = scanner.nextInt();
                if (x == 0) zero++;
                else count++;
            }
            System.out.println(Math.min(zero, count + 1));
        }
    }
}

